#include<bits/stdc++.h>
using namespace std;
const int MAXN=1e5+10;
long long n,L,k,a[MAXN],maxn=0;
bool f(int midx){
	int x=0;
	for(int i=1;i<=n;i++){
        if(a[i]-a[i-1]>midx){
            x+=((a[i]-a[i-1])/midx);
            if((a[i]-a[i-1])%midx==0)x--;
        }   
    }
	return x<=k;
}
int main(void) {
	cin>>L>>n>>k;
	for(int i=1;i<=n;i++)cin>>a[i];
	a[++n]=L;
	long long  l=1,r=L;
	while(l<r){
		long long  mid=(l+r)/2;
		if(f(mid))r=mid;
		else l=mid+1;
	}
	cout<<l;
	return false;
}
